svg.script:
(function () {
  var eye = document.getElementById('eye-scan-controller');
  if (!eye) return;

  var current = { x: 0, y: 0 };
  var lastTarget = null;

  var poses = [
    { x: 0, y: 0 },
    { x: -5.5, y: -1.8 },
    { x: 6.2, y: -1.1 },
    { x: -6.8, y: 2.8 },
    { x: 6.8, y: 2.3 },
    { x: 0.6, y: -4.3 },
    { x: -0.8, y: 4.1 },
    { x: -3.1, y: 0.9 },
    { x: 3.3, y: -2.7 },
    { x: -7.6, y: 0.3 },
    { x: 7.4, y: 0.5 }
  ];

  function rand(min, max) {
    return Math.random() * (max - min) + min;
  }

  function easeInOut(t) {
    return t < 0.5
      ? 2 * t * t
      : 1 - Math.pow(-2 * t + 2, 2) / 2;
  }

  function apply(x, y) {
    eye.setAttribute('transform', 'translate(' + x.toFixed(2) + ' ' + y.toFixed(2) + ')');
  }

  function chooseTarget() {
    // Center pause now and then so the motion feels more like scanning.
    if (Math.random() < 0.22) return { x: 0, y: 0 };

    var target = poses[Math.floor(Math.random() * poses.length)];
    while (lastTarget && target.x === lastTarget.x && target.y === lastTarget.y) {
      target = poses[Math.floor(Math.random() * poses.length)];
    }

    // Tiny jitter keeps the stare from feeling robotic.
    target = {
      x: target.x + rand(-0.45, 0.45),
      y: target.y + rand(-0.35, 0.35)
    };

    lastTarget = target;
    return target;
  }

  function moveTo(target, duration, hold) {
    var start = { x: current.x, y: current.y };
    var startTime = null;

    function frame(ts) {
      if (startTime === null) startTime = ts;
      var p = Math.min(1, (ts - startTime) / duration);
      var e = easeInOut(p);
      var x = start.x + (target.x - start.x) * e;
      var y = start.y + (target.y - start.y) * e;
      apply(x, y);

      if (p < 1) {
        requestAnimationFrame(frame);
      } else {
        current = target;
        setTimeout(nextMove, hold);
      }
    }

    requestAnimationFrame(frame);
  }

  function nextMove() {
    var target = chooseTarget();
    var distance = Math.hypot(target.x - current.x, target.y - current.y);
    var duration = 180 + distance * 38 + rand(80, 260);
    var hold = rand(550, 2100);

    // Occasional longer stare to sell the surveillance vibe.
    if (Math.random() < 0.14) hold += rand(900, 1700);

    moveTo(target, duration, hold);
  }

  apply(0, 0);
  setTimeout(nextMove, 900 + rand(0, 600));
})();
